/**
 * Synthetic data narratives — the single generator behind BOTH synthetic databases:
 *
 * - `demo`  — rich 8-year life story for the hosted recruiter demo (multi-card, cuotas,
 *             USD statements, property purchase).
 * - `test`  — lean deterministic dataset for Vitest (short window, one card, small
 *             merchant pool) generated by `vitest.globalSetup` so the suite never copies
 *             personal data.
 *
 * All money flows originate from one checking account plus the configured credit cards —
 * the same "master moves" model the reconciliation engine expects — so every derived
 * surface (deposits matching, billing months, gastos categories, net-worth buckets) is
 * internally consistent by construction.
 *
 * Both presets end at the CURRENT calendar month so current-month/rollover code paths
 * always have data; the seed keeps the history deterministic for a given month.
 */
import { monthKeyFromYmd } from "../calendarMonth.js";
import { chileCalendarTodayYmd } from "../chileDate.js";

/** `YYYY-MM`. */
export type DemoMonth = string;

export type DemoPreset = "demo" | "test";

export type DemoChapterId =
  | "first_job_at_parents"
  | "first_apartment"
  | "pandemic_lockdown"
  | "back_with_parents"
  | "renting_again"
  | "own_house"
  | "test_baseline";

export type DemoChapter = {
  id: DemoChapterId;
  /** Inclusive start month. Chapter runs until the next chapter's start. */
  from: DemoMonth;
  /** Net monthly salary landing in checking (CLP). Grows by `salaryAnnualGrowth`. */
  salaryClp: number;
  salaryAnnualGrowth: number;
  /** Fixed monthly outflows from checking (rent/mortgage, bills, fees). */
  fixedExpensesClp: number;
  /** Mean discretionary CC spend per month across all cards. */
  ccSpendMeanClp: number;
  /** Fraction of leftover cash swept to investments/savings each month (0–1). */
  savingsRate: number;
  /** Weight multipliers per gastos category for this chapter (supermarket, fun, …). */
  categoryWeights?: Record<string, number>;
};

export type DemoEventKind =
  | "moving_costs"
  | "vacation_small"
  | "vacation_medium"
  | "vacation_big"
  | "house_down_payment"
  | "bonus";

export type DemoEvent = {
  month: DemoMonth;
  kind: DemoEventKind;
  /** Positive = extra spend (CC unless `viaChecking`), negative = extra income. */
  amountClp: number;
  viaChecking?: boolean;
  /** Big purchases can bill as N cuotas on the card (exercises installment views). */
  cuotas?: number;
  label: string;
  /** last4 of the card the event bills on (defaults to the first active card). */
  cardLast4?: string;
};

export type DemoCard = {
  last4: string;
  cardGroup: "santander" | "bci";
  displayName: string;
  /** First month the card exists (statements start here). */
  from: DemoMonth;
  /** Relative share of the chapter's discretionary spend once active. */
  spendShare: number;
  /** Extra category weight multipliers stacked on the chapter's (per-card flavor). */
  merchantBias?: Record<string, number>;
  /** Monthly international USD purchases (adds a USD statement per month). */
  usdMonthly?: { meanUsd: number };
};

export type DemoNarrative = {
  preset: DemoPreset;
  /** Deterministic PRNG seed — same seed + same month, same DB. */
  seed: number;
  firstMonth: DemoMonth;
  /** Always the current calendar month — the demo/test data never goes stale. */
  lastMonth: DemoMonth;
  chapters: DemoChapter[];
  events: DemoEvent[];
  cards: DemoCard[];
  /** Investment accounts to create (fondo always; AFP/property optional). */
  withAfp: boolean;
  withProperty: boolean;
};

function currentMonth(): DemoMonth {
  return monthKeyFromYmd(chileCalendarTodayYmd());
}

function monthsBack(n: number): DemoMonth {
  const cur = currentMonth();
  let y = Number(cur.slice(0, 4));
  let m = Number(cur.slice(5, 7)) - n;
  while (m <= 0) {
    m += 12;
    y -= 1;
  }
  return `${y}-${String(m).padStart(2, "0")}`;
}

