/**
 * Lean Vitest narrative: ~18 months, one card, one cuota purchase (so installment-ledger
 * paths have rows), AFP + fondo for bucket coverage, no property. Deterministic for a
 * given calendar month.
 */
function testNarrative(): DemoNarrative {
  const first = monthsBack(17);
  return {
    preset: "test",
    seed: 424242,
    firstMonth: first,
    lastMonth: currentMonth(),
    chapters: [
      {
        id: "test_baseline",
        from: first,
        salaryClp: 1_500_000,
        salaryAnnualGrowth: 0.05,
        fixedExpensesClp: 450_000,
        ccSpendMeanClp: 300_000,
        savingsRate: 0.35,
      },
    ],
    events: [
      { month: monthsBack(9), kind: "vacation_medium", amountClp: 600_000, cuotas: 6, label: "Viaje test" },
      { month: monthsBack(3), kind: "vacation_small", amountClp: 200_000, label: "Escapada test" },
    ],
    cards: [
      {
        last4: "4321",
        cardGroup: "santander",
        displayName: "Tarjeta · Test Bank 4321",
        from: first,
        spendShare: 1,
        usdMonthly: { meanUsd: 80 },
      },
      {
        last4: "6605",
        cardGroup: "bci",
        displayName: "Tarjeta · Test Retail 6605",
        from: monthsBack(11),
        spendShare: 0.4,
      },
    ],
    withAfp: true,
    withProperty: false,
  };
}

export function demoNarrativeForPreset(preset: DemoPreset): DemoNarrative {
  return preset === "test" ? testNarrative() : demoNarrative();
}

/** Chapter in effect for a month (chapters sorted by `from`; last one whose from ≤ month). */
export function chapterForMonth(narrative: DemoNarrative, month: DemoMonth): DemoChapter {
  const sorted = [...narrative.chapters].sort((a, b) => a.from.localeCompare(b.from));
  let current = sorted[0];
  if (!current) throw new Error("demo narrative needs at least one chapter");
  for (const ch of sorted) {
    if (ch.from <= month) current = ch;
  }
  return current;
}

/** Deterministic mulberry32 PRNG — same narrative seed ⇒ identical DB. */
export function demoRng(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
